/**
 * BYOP Connect module — Pollinations Redirect Flow (AMD build).
 *
 * @module     aiprovider_pollinations/byop_connect
 * @copyright  2026 Krissy Painter
 * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
define('aiprovider_pollinations/byop_connect', [
    'core/ajax',
    'core/notification'
], function(Ajax, Notification) {

    var AUTHORIZE_URL = 'https://enter.pollinations.ai/authorize';
    var APP_KEY = 'pk_JpcODXmxY8ORHqe6';

    /**
     * Initialise the BYOP connect UI.
     */
    function init() {
        var container = document.getElementById('aiprovider_pollinations_byop_container');
        if (!container) {
            return;
        }

        container.innerHTML = '';
        container.style.padding = '10px 0';

        // Status display.
        var statusDiv = document.createElement('div');
        statusDiv.id = 'aiprovider_pollinations_status';
        statusDiv.style.marginBottom = '10px';
        container.appendChild(statusDiv);

        // Connect button.
        var connectBtn = document.createElement('button');
        connectBtn.type = 'button';
        connectBtn.className = 'btn btn-primary';
        connectBtn.textContent = '🔗 Connect to Pollinations';
        connectBtn.style.marginRight = '8px';
        connectBtn.addEventListener('click', startRedirectFlow);
        container.appendChild(connectBtn);

        // Disconnect button.
        var disconnectBtn = document.createElement('button');
        disconnectBtn.type = 'button';
        disconnectBtn.className = 'btn btn-secondary';
        disconnectBtn.textContent = 'Disconnect';
        disconnectBtn.style.display = 'none';
        disconnectBtn.addEventListener('click', disconnect);
        container.appendChild(disconnectBtn);

        checkStatus();
    }

    /**
     * Start the BYOP redirect flow in a popup window.
     */
    function startRedirectFlow() {
        var state = Math.random().toString(36).substring(2, 15);
        sessionStorage.setItem('pollinations_byop_state', state);

        var params = new URLSearchParams({
            redirect_uri: window.location.href.split('#')[0],
            client_id: APP_KEY,
            state: state
        });

        var authUrl = AUTHORIZE_URL + '?' + params.toString();
        var popup = window.open(authUrl, 'pollinations_auth', 'width=600,height=700,scrollbars=yes');

        if (!popup) {
            showStatus('❌ Popup blocked. Please allow popups for this page and try again.', 'error');
            return;
        }

        var pollTimer = setInterval(function() {
            try {
                if (popup.closed) {
                    clearInterval(pollTimer);
                    checkStatus();
                    return;
                }

                if (popup.location.hostname === window.location.hostname) {
                    var hash = popup.location.hash;
                    var hashParams = new URLSearchParams(hash.slice(1));
                    var apiKey = hashParams.get('api_key');
                    var error = hashParams.get('error');
                    var returnedState = hashParams.get('state');

                    if (error) {
                        clearInterval(pollTimer);
                        popup.close();
                        showStatus('❌ Authorization denied.', 'error');
                        return;
                    }

                    if (apiKey) {
                        clearInterval(pollTimer);

                        var savedState = sessionStorage.getItem('pollinations_byop_state');
                        if (returnedState && savedState && returnedState !== savedState) {
                            popup.close();
                            showStatus('❌ Security check failed. Please try again.', 'error');
                            return;
                        }

                        saveKey(apiKey).then(function() {
                            popup.close();
                            sessionStorage.removeItem('pollinations_byop_state');
                            showStatus('✅ Successfully connected to Pollinations!', 'success');
                            toggleButtons(true);
                        }).catch(Notification.exception);
                    }
                }
            } catch (e) {
                // Cross-origin — popup still on Pollinations, keep waiting.
            }
        }, 500);

        setTimeout(function() {
            if (!popup.closed) {
                clearInterval(pollTimer);
                popup.close();
                showStatus('⏰ Authorization timed out. Please try again.', 'error');
            }
        }, 300000);
    }

    /**
     * Save the API key via the external API.
     *
     * @param {string} apikey
     * @return {Promise}
     */
    function saveKey(apikey) {
        var request = {
            methodname: 'aiprovider_pollinations_save_key',
            args: {apikey: apikey}
        };
        return Ajax.call([request])[0];
    }

    /**
     * Disconnect by clearing the stored API key.
     */
    function disconnect() {
        var request = {
            methodname: 'aiprovider_pollinations_disconnect',
            args: {}
        };
        Ajax.call([request])[0].then(function() {
            showStatus('Disconnected from Pollinations.', 'info');
            toggleButtons(false);
            return;
        }).catch(Notification.exception);
    }

    /**
     * Check current connection status and update UI.
     */
    function checkStatus() {
        var request = {
            methodname: 'aiprovider_pollinations_get_status',
            args: {}
        };
        Ajax.call([request])[0].then(function(result) {
            if (result.connected) {
                var msg = '✅ Connected to Pollinations';
                if (result.balance !== undefined && result.balance !== null) {
                    msg += ' — Balance: ' + result.balance + ' pollen';
                }
                showStatus(msg, 'success');
                toggleButtons(true);
            } else {
                showStatus('⚪ Not connected. Click "Connect to Pollinations" to get started.', 'info');
                toggleButtons(false);
            }
            return;
        }).catch(function() {
            showStatus('⚪ Not connected. Click "Connect to Pollinations" to get started.', 'info');
            return;
        });
    }

    /**
     * Show a status message.
     *
     * @param {string} message
     * @param {string} type
     */
    function showStatus(message, type) {
        var statusDiv = document.getElementById('aiprovider_pollinations_status');
        if (!statusDiv) {
            return;
        }
        statusDiv.textContent = message;
        statusDiv.style.padding = '8px 12px';
        statusDiv.style.borderRadius = '6px';
        statusDiv.style.marginBottom = '10px';

        switch (type) {
            case 'success':
                statusDiv.style.backgroundColor = '#d4edda';
                statusDiv.style.color = '#155724';
                statusDiv.style.border = '1px solid #c3e6cb';
                break;
            case 'error':
                statusDiv.style.backgroundColor = '#f8d7da';
                statusDiv.style.color = '#721c24';
                statusDiv.style.border = '1px solid #f5c6cb';
                break;
            default:
                statusDiv.style.backgroundColor = '#e2e3e5';
                statusDiv.style.color = '#383d41';
                statusDiv.style.border = '1px solid #d6d8db';
        }
    }

    /**
     * Toggle connect/disconnect button visibility.
     *
     * @param {bool} connected
     */
    function toggleButtons(connected) {
        var buttons = document.querySelectorAll('#aiprovider_pollinations_byop_container button');
        if (buttons.length >= 2) {
            buttons[0].style.display = connected ? 'none' : 'inline-block';
            buttons[1].style.display = connected ? 'inline-block' : 'none';
        }
    }

    return {
        init: init
    };
});
